package com.projectbible.post.maven.jdbc.postgresql.post.presentation;
import com.projectbible.post.maven.jdbc.postgresql.common.api.ApiResponse; import com.projectbible.post.maven.jdbc.postgresql.post.application.PostQueryService; import io.swagger.v3.oas.annotations.Operation; import io.swagger.v3.oas.annotations.tags.Tag; import java.util.List; import java.util.Map; import org.springframework.web.bind.annotation.*;
@Tag(name="posts") @RestController @RequestMapping("/api/v1/posts") public class PostController { private final PostQueryService service; public PostController(PostQueryService service) { this.service=service; } @Operation(summary="List posts") @GetMapping public ApiResponse<List<Map<String,Object>>> list(@RequestParam(required=false) Long boardId) { List<Map<String,Object>> items=service.list(boardId); return ApiResponse.success(items,Map.of("page",1,"limit",items.size(),"totalCount",items.size(),"totalPages",1)); } @Operation(summary="Get post detail") @GetMapping("/{postId}") public ApiResponse<Map<String,Object>> one(@PathVariable long postId) { return ApiResponse.success(service.one(postId)); } }
